mapper.select:
SELECT MAX(last_seen_at)
FROM index_constituent
WHERE index_code = #{indexCode}

mapper.update:
UPDATE index_constituent
SET current_member = FALSE
WHERE index_code = #{indexCode}

mapper.select:
SELECT COUNT(*)
FROM index_constituent
WHERE index_code = #{indexCode}

SELECT i.symbol FROM index_constituent i LEFT JOIN stock_symbol s ON s.symbol = i.symbol WHERE i.current_member = TRUE AND i.symbol NOT IN ('TICKER', 'SECURITY') AND UPPER(COALESCE(i.sector, '')) <> 'TICKER' AND i.index_code IN
#{indexCode}
GROUP BY i.symbol ORDER BY MAX(CASE WHEN s.last_collected_at IS NULL THEN 1 ELSE 0 END) DESC, MIN(s.last_collected_at), i.symbol LIMIT #{limit}

SELECT p.symbol, p.name, p.logo, ic.sector, p.finnhub_industry AS industry, p.market_cap, inst.shares_change_pct AS institutionSharesChangePct, inst.holder_count AS institutionHolderCount, inst.report_quarter AS institutionReportQuarter, q.current_price, q.previous_close, q.open_price, q.high_price, q.low_price, highs.three_month_high AS threeMonthHigh, m.pe_normalized_annual, m.pb_annual, m.roe_ttm, sl.integrated_score AS signalScore, sl.confidence AS signalConfidence, sl.tone AS signalTone, sl.calculated_at AS signalCalculatedAt, dq.quality_score AS dataQualityScore, dq.quality_label AS dataQualityLabel, dq.tone AS dataQualityTone, dq.excluded_fields_json AS dataQualityExcludedFieldsJson, sl.valuation_score AS valuationScore, sl.quality_score AS qualityScore, sl.growth_score AS growthScore, sl.stability_score AS stabilityScore, sl.earnings_score AS earningsScore, sl.analyst_score AS analystScore, sl.news_score AS newsScore, sl.momentum_score AS momentumScore, sl.risk_score AS riskScore FROM company_profile p LEFT JOIN ( SELECT symbol, MIN(sector) AS sector FROM index_constituent WHERE current_member = TRUE GROUP BY symbol ) ic ON ic.symbol = p.symbol LEFT JOIN stock_quote_cache q ON q.symbol = p.symbol LEFT JOIN (
) highs ON highs.symbol = p.symbol LEFT JOIN stock_institution_flow_quarterly inst ON inst.symbol = p.symbol AND inst.report_quarter = ( SELECT MAX(report_quarter) FROM stock_institution_flow_quarterly WHERE symbol = p.symbol ) LEFT JOIN stock_metric_snapshot m ON m.symbol = p.symbol AND m.metric_date = ( SELECT MAX(metric_date) FROM stock_metric_snapshot WHERE symbol = p.symbol ) LEFT JOIN stock_signal_latest sl ON sl.symbol = p.symbol LEFT JOIN stock_data_quality_latest dq ON dq.symbol = p.symbol WHERE p.symbol IN
#{symbol}
ORDER BY p.market_cap DESC, p.symbol
